pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

contract SafeExecutor is Ownable {
    // Never call a user supplied target with user supplied calldata.
    // Maintain an allowlist of known, audited targets:
    mapping(address => bool) public allowedTargets;

    function setTarget(address target, bool allowed) external onlyOwner {
        allowedTargets[target] = allowed;
    }

    function execute(address target, bytes calldata data) external {
        // 1. Checks: only pre approved targets, never delegatecall
        require(allowedTargets[target], "target not allowed");

        // 2. Effects: update internal state BEFORE the external call
        //    (checks-effects-interactions)

        // 3. Interactions: plain call only, and verify success
        (bool ok, ) = target.call(data);
        require(ok, "external call failed");
    }

    // If the use case is a specific action (e.g. token transfer),
    // expose that action directly instead of a generic call:
    // function payOut(address payable to, uint256 amount) external onlyOwner { ... }
}
